module top_module(CLK, EN, TE, DATA, Q);input CLK, EN, TE;
  input [31:0] DATA;
  output reg [31:0] Q;

  wire gated_clk;

  assign gated_clk = (EN && !TE) ? CLK : 1'b0;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge gated_clk or posedge dbg_halt) begin
    if (EN && !TE) begin
      Q <= DATA;
    end
  end

endmodule
